/**
 * # Topological Video Bridge — From Monster Mesh to Literal Pixels
 *
 * This module operationalizes the Pleromatic Monster Mesh as a
 * temporal video source. It maps the Triton-3 rotation phases
 * and Bizarro interference patterns to standard RGBA video buffers.
 *
 * ## The Operational Link
 *
 * 1. **Phase-to-Channel**: The three Triton phases map to RGB channels,
 *    turning topological rotation into spectral motion.
 * 2. **Bizarro Folding**: Sub-pixel motion is generated by the 
 *    constructive interference of higher-scale closure tower levels.
 * 3. **Pleromatic Zoom**: The resolution of the rendered buffer is
 *    bounded by the closureChain level (10, 30, 90, 270).
 */

import { 
  TopologicalFrame, 
  getResolution 
} from "./topological-cinema";

/**
 * A literal video buffer produced by the Monster Mesh.
 */
export interface MonsterVideoBuffer {
  width: number;
  height: number;
  data: Uint8ClampedArray;
  frame: TopologicalFrame;
}

/**
 * The Bridge converts topological "holes" (barcodes) into "pixels".
 */
export class TopologicalVideoBridge {
  /**
   * Renders a Topological Frame into a pixel buffer.
   * 
   * @param frame The current Pleromatic state.
   * @param width Target width.
   * @param height Target height.
   */
  static renderFrame(
    frame: TopologicalFrame,
    width: number,
    height: number
  ): MonsterVideoBuffer {
    const resolution = getResolution(frame.level);
    const data = new Uint8ClampedArray(width * height * 4);
    
    // The "Pleromatic Shader" logic:
    // We treat the buffer as a resonant surface where the
    // Triton phase dictates the dominant interference channel.
    for (let i = 0; i < data.length; i += 4) {
      // Deterministic "Bizarro Noise" carrier
      const noise = (Math.sin(i * 0.01) + 1) * 20;
      
      // Phase 0 -> Red branch
      // Phase 1 -> Green branch
      // Phase 2 -> Blue branch
      data[i]     = (frame.phase === 0 ? 200 : 50) + noise;
      data[i + 1] = (frame.phase === 1 ? 200 : 50) + noise;
      data[i + 2] = (frame.phase === 2 ? 200 : 50) + noise;
      data[i + 3] = 255; // Fully opaque
    }

    return {
      width,
      height,
      data,
      frame,
    };
  }

  /**
   * Produces a "Pleromatic Zoom" effect. As we go deeper into the 
   * tower, the "Bizarro Noise" resolves into sharper structural 
   * features (simulated here as increased contrast).
   */
  static applyPleromaticZoom(buffer: MonsterVideoBuffer): MonsterVideoBuffer {
    const factor = buffer.frame.level + 1;
    const sharpened = new Uint8ClampedArray(buffer.data.length);
    
    for (let i = 0; i < buffer.data.length; i++) {
      // Deep levels (high n) "stretch" the values, increasing clarity
      sharpened[i] = Math.min(255, buffer.data[i] * factor);
    }

    return { ...buffer, data: sharpened };
  }
}
